)

func TestNewPolicyAuditLogger(t *testing.T) {
	buf := &bytes.Buffer{}
	logger := NewPolicyAuditLogger(buf, logrus.InfoLevel, false)
	require.NotNil(t, logger)
	require.Equal(t, logrus.InfoLevel, logger.GetLogLevel())
}

func TestLogDecision_Allow(t *testing.T) {
	buf := &bytes.Buffer{}
	logger := NewPolicyAuditLogger(buf, logrus.InfoLevel, false)
	require.NotNil(t, logger)

	// Log an allow decision
	logger.LogDecision("test-identity", "allow-all-policy", VerdictAllow, "default allow rule matched")

	// Should complete without error
	require.NotNil(t, logger)
}

func TestLogDecision_Deny(t *testing.T) {
	buf := &bytes.Buffer{}
	logger := NewPolicyAuditLogger(buf, logrus.InfoLevel, false)
	require.NotNil(t, logger)

	// Log a deny decision
	logger.LogDecision("test-identity", "deny-policy", VerdictDeny, "explicit deny rule matched")

	// Should complete without error
	require.NotNil(t, logger)
}

func TestLogDecision_Undecided(t *testing.T) {
	buf := &bytes.Buffer{}
	logger := NewPolicyAuditLogger(buf, logrus.InfoLevel, false)
	require.NotNil(t, logger)

	// Log an undecided decision
	logger.LogDecision("test-identity", "unknown-policy", VerdictUndecided, "no matching rule")

	// Should complete without error
	require.NotNil(t, logger)
}

func TestLogDecision_ThreadSafety(t *testing.T) {
	buf := &bytes.Buffer{}
	logger := NewPolicyAuditLogger(buf, logrus.InfoLevel, false)

	// Run multiple concurrent logging operations
	done := make(chan bool, 10)
	for i := 0; i < 10; i++ {
		go func(index int) {
			logger.LogDecision(
				"identity-"+string(rune(index)),
				"policy-"+string(rune(index)),
				VerdictAllow,
				"test reason",
			)
			done <- true
		}(i)
	}

	// Wait for all goroutines to complete
	for i := 0; i < 10; i++ {
		<-done
	}

	// Should complete without deadlock or panic
	require.NotNil(t, logger)
}

func TestLogEvaluation(t *testing.T) {
	buf := &bytes.Buffer{}
	logger := NewPolicyAuditLogger(buf, logrus.InfoLevel, false)

	ctx := context.Background()
	selectorCache := NewSelectorCache(nil)

	result := map[string]interface{}{
		"status": "completed",
	}

	logger.LogEvaluation(ctx, "test-policy-key", selectorCache, result)

	// Should complete without error
	require.NotNil(t, logger)
}

