	buf := &bytes.Buffer{}
	logger := NewPolicyAuditLogger(buf, logrus.InfoLevel, false)

	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()

	selectorCache := NewSelectorCache(nil)
	result := "evaluation-successful"

	logger.LogEvaluation(ctx, "context-aware-policy", selectorCache, result)

	// Should complete without error
	require.NotNil(t, logger)
}

