	require.Equal(t, logrus.InfoLevel, logger.GetLogLevel())

	logger.SetLogLevel(logrus.DebugLevel)
	require.Equal(t, logrus.DebugLevel, logger.GetLogLevel())

	logger.SetLogLevel(logrus.WarnLevel)
	require.Equal(t, logrus.WarnLevel, logger.GetLogLevel())
}

func TestGetLogLevel(t *testing.T) {
	buf := &bytes.Buffer{}
	logger := NewPolicyAuditLogger(buf, logrus.DebugLevel, false)

	level := logger.GetLogLevel()
	require.Equal(t, logrus.DebugLevel, level)
}

func TestPolicyAuditLogger_NilOutput(t *testing.T) {
	// Create logger with nil output - should still work
	logger := NewPolicyAuditLogger(nil, logrus.InfoLevel, false)
	require.NotNil(t, logger)

	// Should handle nil output gracefully
	logger.LogDecision("test", "test", VerdictAllow, "test")
	logger.LogEvaluation(context.Background(), "test", nil, nil)

	require.NotNil(t, logger)
}

func TestAuditVerdictType_String(t *testing.T) {
	require.Equal(t, AuditVerdictType("allow"), VerdictAllow)
	require.Equal(t, AuditVerdictType("deny"), VerdictDeny)
	require.Equal(t, AuditVerdictType("undecided"), VerdictUndecided)
}

func TestLogEvaluation_NilSelectorCache(t *testing.T) {
	buf := &bytes.Buffer{}
	logger := NewPolicyAuditLogger(buf, logrus.InfoLevel, false)

	// Should handle nil SelectorCache gracefully
	logger.LogEvaluation(context.Background(), "policy-key", nil, "result")

	require.NotNil(t, logger)
}

func TestLogDecision_MultipleVerdicts(t *testing.T) {
	buf := &bytes.Buffer{}
	logger := NewPolicyAuditLogger(buf, logrus.InfoLevel, false)

	verdicts := []AuditVerdictType{VerdictAllow, VerdictDeny, VerdictUndecided}

	for _, verdict := range verdicts {
		logger.LogDecision("test-identity", "policy", verdict, "test reason")
	}

	require.NotNil(t, logger)
}

func TestLogIdentityDecision_MultipleIdentities(t *testing.T) {
	buf := &bytes.Buffer{}
	logger := NewPolicyAuditLogger(buf, logrus.InfoLevel, false)

	for i := identity.NumericIdentity(1000); i < identity.NumericIdentity(1010); i++ {
		logger.LogIdentityDecision(i, "policy-"+i.String(), VerdictAllow, "test")
	}

	require.NotNil(t, logger)
}

